import React, { useState } from "react";
import { isConnected, requestAccess } from "@stellar/freighter-api";
import axios from "axios";

function App() {
  const [buyer, setBuyer] = useState("");
  const [seller, setSeller] = useState("");
  const [credits, setCredits] = useState("");
  const [wallet, setWallet] = useState(null);
  const [result, setResult] = useState(null);

  const connectWallet = async () => {
    const response = await isConnected();

    if (!response.isConnected) {
      alert("Freighter not available");
      return;
    }

    const access = await requestAccess();

    if (access.error) {
      alert("Connection failed");
    } else {
      setWallet(access.address);
    }
  };

  const submitTrade = async () => {
    try {
      const response = await axios.post("http://localhost:5000/trade", {
        buyer: buyer,
        seller: seller,
        credits: Number(credits),
      });

      setResult(response.data);
    } catch (error) {
      console.error(error);
      alert("Error sending trade");
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Carbon Trading UI</h2>

      <input
        type="text"
        placeholder="Buyer"
        value={buyer}
        onChange={(e) => setBuyer(e.target.value)}
      />
      <br /><br />

      <input
        type="text"
        placeholder="Seller"
        value={seller}
        onChange={(e) => setSeller(e.target.value)}
      />
      <br /><br />

      <input
        type="number"
        placeholder="Credits"
        value={credits}
        onChange={(e) => setCredits(e.target.value)}
      />
      <br /><br />

      <button onClick={connectWallet}>Connect Wallet</button>
      <br /><br />

      <button onClick={submitTrade} disabled={!wallet}>
        Submit
      </button>

      {wallet && <p>Connected: {wallet}</p>}

      {result && (
        <div>
          <p>Hash: {result.hash}</p>
          <p>Transaction ID: {result.transactionId}</p>
        </div>
      )}
    </div>
  );
}

export default App;
